const amqp = require('amqplib');
const { Pool } = require('pg');

const rabbitmqUrl = 'amqp://localhost';
const queueName = 'event_queue';
const dbConfig = {
  user: 'user',
  host: 'localhost',
  database: 'events_db',
  password: 'password',
  port: 5432,
};

const pool = new Pool(dbConfig);

async function connectToRabbitMQ() {
  try {
    const connection = await amqp.connect(rabbitmqUrl);
    const channel = await connection.createChannel();
    await channel.assertQueue(queueName, { durable: true });
    channel.prefetch(1);
    return { connection, channel };
  } catch (error) {
    console.error('Failed to connect to RabbitMQ:', error);
    process.exit(1);
  }
}

async function processMessage(channel, msg) {
  try {
    const messageContent = msg.content.toString();
    const parsedMessage = JSON.parse(messageContent);
    
    const { type, payload } = parsedMessage;
    
    switch (type) {
      case 'CREATE_USER':
        await createUser(payload);
        break;
      case 'UPDATE_USER':
        await updateUser(payload);
        break;
      case 'DELETE_USER':
        await deleteUser(payload);
        break;
      default:
        console.warn(`Unknown message type: ${type}`);
    }
    
    channel.ack(msg);
  } catch (error) {
    console.error('Error processing message:', error);
    channel.nack(msg, false, false);
  }
}

async function createUser(userData) {
  const { name, email } = userData;
  
  if (!name || !email) {
    throw new Error('Missing required fields');
  }
  
  const query = 'INSERT INTO users(name, email) VALUES($1, $2) RETURNING id';
  const values = [name, email];
  
  const result = await pool.query(query, values);
  console.log('User created with ID:', result.rows[0].id);
}

async function updateUser(userData) {
  const { id, name, email } = userData;
  
  if (!id) {
    throw new Error('Missing user ID');
  }
  
  const updates = [];
  const values = [];
  let index = 1;
  
  if (name !== undefined) {
    updates.push(`name = $${index}`);
    values.push(name);
    index++;
  }
  
  if (email !== undefined) {
    updates.push(`email = $${index}`);
    values.push(email);
    index++;
  }
  
  if (updates.length === 0) {
    throw new Error('No fields to update');
  }
  
  values.push(id);
  const query = `UPDATE users SET ${updates.join(', ')} WHERE id = $${index} RETURNING id`;
  
  await pool.query(query, values);
  console.log('User updated');
}

async function deleteUser(userData) {
  const { id } = userData;
  
  if (!id) {
    throw new Error('Missing user ID');
  }
  
  const query = 'DELETE FROM users WHERE id = $1 RETURNING id';
  const values = [id];
  
  const result = await pool.query(query, values);
  
  if (result.rowCount === 0) {
    console.warn('User not found for deletion');
  } else {
    console.log('User deleted');
  }
}

async function startMicroservice() {
  const { channel } = await connectToRabbitMQ();
  
  channel.consume(queueName, (msg) => processMessage(channel, msg), { noAck: false });
  
  console.log('Microservice started and waiting for messages...');
}

startMicroservice();